class HopcroftKarp:
    def __init__(self, V_left, V_right):
        self.V_left = V_left
        self.V_right = V_right
        self.graph = [[] for _ in range(V_left + V_right)]
        self.match = [-1] * (V_left + V_right)
        self.dist = [-1] * (V_left + V_right)
        self.ptr = [0] * (V_left + V_right)

    def add_edge(self, u, v):
        self.graph[u].append(v)

    def bfs(self):
        queue = []
        for u in range(self.V_left):
            if self.match[u] == -1:
                self.dist[u] = 0
                queue.append(u)
            else:
                self.dist[u] = -1

        for v_idx in range(self.V_right):
            v = self.V_left + v_idx
            self.dist[v] = -1

        head = 0
        found_augmenting_path = False

        while head < len(queue):
            u = queue[head]
            head += 1

            for v in self.graph[u]:
                if self.dist[v] == -1:
                    self.dist[v] = self.dist[u] + 1

                    if self.match[v] == -1:
                        found_augmenting_path = True
                    else:
                        if self.dist[self.match[v]] == -1:
                             self.dist[self.match[v]] = self.dist[v] + 1
                             queue.append(self.match[v])
        return found_augmenting_path

    def dfs(self, u):
        for i in range(self.ptr[u], len(self.graph[u])):
            self.ptr[u] = i
            v = self.graph[u][i]

            if self.dist[v] == self.dist[u] + 1:
                if self.match[v] == -1 or \
                   (self.dist[self.match[v]] != -1 and self.dist[self.match[v]] == self.dist[v] + 1 and self.dfs(self.match[v])):
                    self.match[v] = u
                    self.match[u] = v
                    return True
        return False

    def max_matching(self):
        matching_size = 0
        while self.bfs():
            self.ptr = [0] * (self.V_left + self.V_right)
            for u in range(self.V_left):
                if self.match[u] == -1:
                    if self.dfs(u):
                        matching_size += 1
        return matching_size
